# Phase 29: 持久化当前教学话题
try:
    if self._persistence:
        # 从 intent 推断 topic (非 general 时比较可信)
        if intent and intent != "general" and intent != "suggest_options":
            old = self._persistence.load_learning_goal()
            if not old:
                self._persistence.save_learning_goal(intent)
        # 每轮保存 current_topic (非 suggest_options 时)
        if intent != "suggest_options":
            self._persistence.save_current_topic(intent or "general")
except Exception:
    pass
